sql_answer:
SELECT 
  100.0 * SUM(CASE WHEN m.built_year < 1850 THEN 1 ELSE 0 END) / COUNT(*) AS percent_before_1850
FROM mill AS m;

SELECT b.name
FROM bridge AS b
WHERE b.length_meters > (
    SELECT AVG(length_meters) FROM bridge
);

SELECT DISTINCT b.location
FROM bridge AS b
JOIN mill   AS m ON b.location = m.location;

SELECT a.Airport_Name
FROM airport AS a
WHERE a.Total_Passengers > 20000000;

SELECT 
    SUM(a.Aircraft_Movements) AS Total_Aircraft_Movements
FROM airport AS a;

SELECT 
    ROUND(100.0 * SUM(CASE WHEN ev.fault_status = 'Fixed' THEN 1 ELSE 0 END) / COUNT(*), 2) AS percent_completed
FROM Engineer_Visits AS ev;

SELECT COUNT(*) AS total_apartments
FROM Apartments AS a
WHERE a.apt_type_code IN ('Studio', 'Duplex');

SELECT AVG(julianday(ab.booking_end_date) - julianday(ab.booking_start_date)) AS avg_stay_days
FROM Apartment_Bookings AS ab
WHERE ab.booking_status_code = 'Confirmed';

WITH total AS (
    SELECT COUNT(*) AS total_students
    FROM Student
),
with_allergy AS (
    SELECT COUNT(DISTINCT h.StuID) AS students_with_allergy
    FROM Has_Allergy AS h
)
SELECT CAST(w.students_with_allergy AS REAL) / t.total_students AS allergy_ratio
FROM with_allergy AS w, total AS t;

SELECT 
    SUM(bb.Clean_Jerk) * 1.0 / SUM(bb.Snatch) AS ratio_clean_jerk_to_snatch
FROM body_builder AS bb;

SELECT DISTINCT b.name
FROM browser AS b
ORDER BY b.name;

SELECT br.name
FROM browser AS br
WHERE br.market_share = (
    SELECT MIN(b2.market_share)
    FROM browser AS b2
);

SELECT s.Shop_ID
FROM shop AS s
WHERE s.Address = '1200 Main Street';

SELECT m.Age
FROM member AS m
WHERE m.Name = 'Breton, Robert';

SELECT COUNT(*) AS num_shops_2010
FROM shop
WHERE Open_Year = '2010';

SELECT s.Address
FROM shop AS s
WHERE CAST(s.Num_of_staff AS INT) = (
    SELECT MIN(CAST(Num_of_staff AS INT))
    FROM shop
);

SELECT GROUP_CONCAT(DISTINCT m.Name, ',') AS names
FROM member AS m
WHERE m.Address = 'Waterbury';

SELECT s.Address
FROM shop AS s
WHERE s.Score = (
    SELECT MIN(Score)
    FROM shop
);

SELECT m.Name
FROM member AS m
WHERE m.Level_of_membership = (
    SELECT MAX(Level_of_membership) FROM member
);

SELECT substr(s.Open_Year, -2) AS last_two_digits
FROM shop AS s
WHERE s.Shop_ID = 5;

SELECT MAX(s.Score) - MIN(s.Score) AS score_difference
FROM shop AS s
WHERE s.Open_Year = '2010';
